'use client'
import { useState } from 'react'
import { signIn, getSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'

export default function LoginPage() {
  const router = useRouter()
  const [form, setForm] = useState({ email: '', password: '' })
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')

    const res = await signIn('credentials', {
      email: form.email,
      password: form.password,
      redirect: false,
    })

    setLoading(false)
    if (res?.error) {
      setError('Invalid email or password. Please try again.')
    } else {
      const session = await getSession()
      const role = (session?.user as any)?.role
      if (role === 'SUPER_ADMIN')       router.push('/super-admin')
      else if (role === 'TENANT_ADMIN') router.push('/tenant-admin')
      else if (role === 'IT_AGENT')     router.push('/dashboard')
      else                              router.push('/portal')
    }
  }

  return (
    <div style={{
      minHeight: '100vh',
      display: 'grid',
      gridTemplateColumns: '1fr 1fr',
      fontFamily: 'var(--font-sans)',
    }}>
      {/* ── Left panel ── */}
      <div style={{
        background: 'linear-gradient(145deg, #0F172A 0%, #1E3A5F 50%, #1E1B4B 100%)',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        padding: '48px 56px',
        position: 'relative',
        overflow: 'hidden',
      }}>
        {/* Background decoration */}
        <div style={{ position:'absolute', top:-120, right:-120, width:400, height:400, borderRadius:'50%', background:'rgba(99,102,241,0.08)', pointerEvents:'none' }} />
        <div style={{ position:'absolute', bottom:-80, left:-80, width:300, height:300, borderRadius:'50%', background:'rgba(37,99,235,0.07)', pointerEvents:'none' }} />

        {/* Logo */}
        <div>
          <div style={{ display:'flex', alignItems:'center', gap:10 }}>
            <div style={{ width:36, height:36, borderRadius:10, background:'linear-gradient(135deg,#3B82F6,#6366F1)', display:'flex', alignItems:'center', justifyContent:'center' }}>
              <span style={{ color:'white', fontWeight:800, fontSize:16 }}>E</span>
            </div>
            <span style={{ color:'white', fontWeight:700, fontSize:20, letterSpacing:'-0.02em' }}>EduDesk</span>
          </div>
        </div>

        {/* Hero text */}
        <div style={{ zIndex:1 }}>
          <div style={{ fontSize:38, fontWeight:800, color:'white', lineHeight:1.18, letterSpacing:'-0.03em', marginBottom:20 }}>
            Your campus helpdesk,<br />
            <span style={{ background:'linear-gradient(90deg,#60A5FA,#818CF8)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>
              reimagined.
            </span>
          </div>
          <p style={{ fontSize:15, color:'rgba(255,255,255,0.55)', lineHeight:1.7, maxWidth:340 }}>
            Submit tickets, track resolutions, and get support from IT — all in one place built for education.
          </p>
        </div>

        {/* Feature chips */}
        <div style={{ display:'flex', gap:8, flexWrap:'wrap', zIndex:1 }}>
          {['🎓 Students', '👨‍🏫 Teachers', '🏢 Staff', '🔐 AD / SSO'].map(f => (
            <div key={f} style={{ background:'rgba(255,255,255,0.07)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:8, padding:'6px 14px', fontSize:12, color:'rgba(255,255,255,0.7)', fontWeight:500 }}>
              {f}
            </div>
          ))}
        </div>
      </div>

      {/* ── Right panel ── */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'center', background:'white', padding:'48px 56px' }}>
        <div style={{ width:'100%', maxWidth:400, animation:'fadeUp 300ms cubic-bezier(0.4,0,0.2,1) both' }}>

          {/* Heading */}
          <div style={{ marginBottom:36 }}>
            <h1 style={{ fontSize:26, fontWeight:800, color:'#0F172A', letterSpacing:'-0.03em', marginBottom:8 }}>
              Welcome back
            </h1>
            <p style={{ fontSize:14, color:'#64748B', fontWeight:400 }}>
              Sign in to your university account to continue.
            </p>
          </div>

          <form onSubmit={handleSubmit}>
            {/* Email */}
            <div style={{ marginBottom:18 }}>
              <label style={{ display:'block', fontSize:12, fontWeight:600, color:'#374151', marginBottom:7, letterSpacing:'0.01em' }}>
                Email Address
              </label>
              <input
                type="email"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                placeholder="you@university.edu"
                autoComplete="username"
                required
                style={{ width:'100%', padding:'11px 14px', border:'1.5px solid #E2E8F0', borderRadius:10, fontSize:14, fontFamily:'var(--font-sans)', outline:'none', boxSizing:'border-box', transition:'border-color 150ms, box-shadow 150ms', color:'#0F172A', background:'#FAFAFA' }}
                onFocus={e => { e.target.style.borderColor='#2563EB'; e.target.style.boxShadow='0 0 0 3px rgba(37,99,235,0.12)'; e.target.style.background='white' }}
                onBlur={e => { e.target.style.borderColor='#E2E8F0'; e.target.style.boxShadow='none'; e.target.style.background='#FAFAFA' }}
              />
            </div>

            {/* Password */}
            <div style={{ marginBottom:24 }}>
              <label style={{ display:'block', fontSize:12, fontWeight:600, color:'#374151', marginBottom:7, letterSpacing:'0.01em' }}>
                Password / AD Password
              </label>
              <input
                type="password"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                placeholder="••••••••"
                autoComplete="current-password"
                required
                style={{ width:'100%', padding:'11px 14px', border:'1.5px solid #E2E8F0', borderRadius:10, fontSize:14, fontFamily:'var(--font-sans)', outline:'none', boxSizing:'border-box', transition:'border-color 150ms, box-shadow 150ms', color:'#0F172A', background:'#FAFAFA' }}
                onFocus={e => { e.target.style.borderColor='#2563EB'; e.target.style.boxShadow='0 0 0 3px rgba(37,99,235,0.12)'; e.target.style.background='white' }}
                onBlur={e => { e.target.style.borderColor='#E2E8F0'; e.target.style.boxShadow='none'; e.target.style.background='#FAFAFA' }}
              />
            </div>

            {/* Error */}
            {error && (
              <div style={{ background:'#FEF2F2', border:'1px solid #FECACA', borderRadius:9, padding:'11px 14px', fontSize:13, color:'#DC2626', marginBottom:20, display:'flex', alignItems:'center', gap:8, fontWeight:500 }}>
                <span>⚠</span> {error}
              </div>
            )}

            {/* Submit */}
            <button
              type="submit"
              disabled={loading}
              style={{
                width:'100%', padding:'13px', border:'none', borderRadius:10, fontSize:14, fontWeight:700, cursor: loading ? 'default' : 'pointer',
                background: loading ? '#93C5FD' : 'linear-gradient(135deg, #2563EB, #1D4ED8)',
                color: 'white',
                boxShadow: loading ? 'none' : '0 2px 8px rgba(37,99,235,0.35)',
                transition: 'all 150ms',
                letterSpacing: '0.01em',
              }}
              onMouseEnter={e => { if (!loading) { (e.target as HTMLElement).style.background='linear-gradient(135deg,#1D4ED8,#1e40af)'; (e.target as HTMLElement).style.boxShadow='0 4px 16px rgba(37,99,235,0.45)'; (e.target as HTMLElement).style.transform='translateY(-1px)' } }}
              onMouseLeave={e => { if (!loading) { (e.target as HTMLElement).style.background='linear-gradient(135deg,#2563EB,#1D4ED8)'; (e.target as HTMLElement).style.boxShadow='0 2px 8px rgba(37,99,235,0.35)'; (e.target as HTMLElement).style.transform='none' } }}
            >
              {loading ? (
                <span style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:8 }}>
                  <span style={{ width:14, height:14, border:'2px solid rgba(255,255,255,0.35)', borderTopColor:'white', borderRadius:'50%', display:'inline-block', animation:'spin 0.7s linear infinite' }} />
                  Signing in…
                </span>
              ) : 'Sign In'}
            </button>
          </form>

          {/* SSO note */}
          <div style={{ marginTop:28, padding:'14px 16px', background:'#F8FAFC', borderRadius:10, border:'1px solid #F1F5F9', display:'flex', gap:12, alignItems:'flex-start' }}>
            <span style={{ fontSize:18, flexShrink:0, marginTop:1 }}>🔐</span>
            <div>
              <div style={{ fontSize:12, fontWeight:700, color:'#374151', marginBottom:4 }}>Active Directory SSO</div>
              <div style={{ fontSize:12, color:'#64748B', lineHeight:1.6 }}>
                Use your university email and AD password. New users can use credentials issued by IT Support.
              </div>
            </div>
          </div>

          {/* Footer */}
          <div style={{ marginTop:32, textAlign:'center', fontSize:11, color:'#CBD5E1', fontFamily:'var(--font-mono)' }}>
            Powered by CloudTitans © 2026 · EduDesk v3.0
          </div>

        </div>
      </div>

      {/* Mobile: hide left panel below 768px via media query — handled via CSS */}
      <style>{`
        @keyframes spin { to { transform: rotate(360deg) } }
        @keyframes fadeUp { from { opacity:0; transform:translateY(16px) } to { opacity:1; transform:none } }
        @media (max-width: 768px) {
          div[style*="gridTemplateColumns"] { grid-template-columns: 1fr !important; }
          div[style*="linear-gradient(145deg"] { display: none !important; }
        }
      `}</style>
    </div>
  )
}
